import jwt
import datetime

def generate_jwt(user_id, role):
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=30)
    }
    
    return jwt.encode(payload, 'secret_key', algorithm='HS256').decode('utf-8')

def authenticate_user(user_id, password):
    # Simulate database lookup (keep this simple for demonstration purposes)
    if user_id == 'admin' and password == 'password':
        return generate_jwt(user_id, role='Admin')
    
    elif user_id == 'user1' and password == 'password':
        return generate_jwt(user_id, role='User')
    
    else:
        raise ValueError('Invalid credentials')

# Example usage
if __name__ == "__main__":
    try:
        token = authenticate_user('admin', 'password')
        print(token)
        
        # Verify the token
        try:
            payload = jwt.decode(token, 'secret_key', algorithms=['HS256'])
            print(payload)
        except jwt.ExpiredSignatureError:
            print("Signature has expired")
        except jwt.InvalidTokenError:
            print("Invalid Token")
    
    except ValueError as e:
        print(f"Error: {str(e)}")